import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"劳动人民文化宫","description":"","frontmatter":{},"headers":[],"relativePath":"parks/cultural-palace.md","filePath":"parks/cultural-palace.md","lastUpdated":1784712887000}'),d={name:"parks/cultural-palace.md"};function n(o,t,i,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="劳动人民文化宫" tabindex="-1">劳动人民文化宫 <a class="header-anchor" href="#劳动人民文化宫" aria-label="Permalink to &quot;劳动人民文化宫&quot;">​</a></h1><blockquote><p>&quot;明清太庙，皇家祭祖圣地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>劳动人民文化宫位于北京市中心，天安门东侧，是明清两代皇帝祭祀祖先的太庙。1950年，改为劳动人民文化宫，成为北京市总工会下属的文化活动场所。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:30-21:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">2元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区东长安街</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="太庙始建" tabindex="-1">太庙始建 <a class="header-anchor" href="#太庙始建" aria-label="Permalink to &quot;太庙始建&quot;">​</a></h3><p>明永乐十八年（1420年），明成祖朱棣按照&quot;左祖右社&quot;的制度，在天安门东侧修建太庙，祭祀祖先。</p><h3 id="明清太庙" tabindex="-1">明清太庙 <a class="header-anchor" href="#明清太庙" aria-label="Permalink to &quot;明清太庙&quot;">​</a></h3><p>明清两代，太庙是皇帝祭祀祖先的圣地，也是皇家祭祖的重要场所。</p><h3 id="改为文化宫" tabindex="-1">改为文化宫 <a class="header-anchor" href="#改为文化宫" aria-label="Permalink to &quot;改为文化宫&quot;">​</a></h3><p>1950年，太庙改为&quot;劳动人民文化宫&quot;，成为北京市总工会下属的文化活动场所，对劳动人民开放。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="太庙" tabindex="-1">太庙 <a class="header-anchor" href="#太庙" aria-label="Permalink to &quot;太庙&quot;">​</a></h3><p>太庙是劳动人民文化宫的核心建筑，是明清皇帝祭祀祖先的地方。</p><h4 id="布局" tabindex="-1">布局 <a class="header-anchor" href="#布局" aria-label="Permalink to &quot;布局&quot;">​</a></h4><p>太庙按照周礼&quot;左祖右社&quot;的制度布局，规模宏大。</p><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>戟门</strong></td><td style="text-align:left;">正门</td></tr><tr><td style="text-align:left;"><strong>前殿</strong></td><td style="text-align:left;">祭祀前准备的地方</td></tr><tr><td style="text-align:left;"><strong>中殿</strong></td><td style="text-align:left;">供奉祖先牌位的地方</td></tr><tr><td style="text-align:left;"><strong>后殿</strong></td><td style="text-align:left;">供奉祖先遗物的地方</td></tr></tbody></table><h3 id="古柏" tabindex="-1">古柏 <a class="header-anchor" href="#古柏" aria-label="Permalink to &quot;古柏&quot;">​</a></h3><p>劳动人民文化宫内有大片古柏林，是明永乐年间种植的，已有600余年历史。</p><h3 id="红墙" tabindex="-1">红墙 <a class="header-anchor" href="#红墙" aria-label="Permalink to &quot;红墙&quot;">​</a></h3><p>劳动人民文化宫的红墙与故宫的红墙相连，是北京中轴线的重要组成部分。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>文化宫游览（约1-2小时）</strong>：</p><p>南门 → 古柏 → 戟门 → 前殿 → 中殿 → 后殿 → 古柏林 → 西门</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线天安门东站B口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、2路、52路等天安门东站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从故宫步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票便宜</strong>：门票仅2元</li><li><strong>人少清静</strong>：比故宫人少很多</li><li><strong>古柏壮观</strong>：600年古柏值得一看</li><li><strong>结合游览</strong>：可与天安门广场、故宫一起游览</li><li><strong>红墙拍照</strong>：红墙非常适合拍照</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">世界最大广场</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">明清皇宫</td></tr><tr><td style="text-align:left;">国家博物馆</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">国家级博物馆</td></tr><tr><td style="text-align:left;">中山公园</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">明清社稷坛</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>劳动人民文化宫是明清太庙，是中国古代宗庙礼制的重要遗存。</p><p>劳动人民文化宫与故宫、中山公园相对应，体现了中国古代&quot;左祖右社&quot;的礼制。</p><hr><p><strong>📍 地址</strong>：北京市东城区东长安街 <strong>📞 电话</strong>：010-65116741</p>',38)])])}const c=e(d,[["render",n]]);export{f as __pageData,c as default};
